-- W1.6 questions batch 7600/9310 (10)

INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('policepromo-8b7f1efc-moex-00059', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-a9c8f8e6', 'sub-policepromo-8b7f1efc-01', NULL, 'essay', '經營生活雜貨店的乙將店內所要淘汰的瑕疵商品堆放在店門口，並且貼
了一張小公告：「有需要者，都可免費帶走」。某日傍晚，甲趁四下無人時，
將其中一個馬克杯取走，但甲並未看到公告，不知乙有同意任何人免費帶
走。甲才離開店門口幾步，赫然發現杯子底部有一處不小的缺角，甚為失
望，趕緊回頭將該杯子放回原本的堆放處。試問甲之刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "5f10b1dfba27", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法實務", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00060', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-a9c8f8e6', 'sub-policepromo-8b7f1efc-01', NULL, 'essay', '丙因涉嫌行賄公務員而受刑事偵查。證人甲為丙之配偶。檢察官在訊問
甲時，疏忽未告知其可拒絕證言。雖然甲目睹行賄過程，但對於檢察官
之訊問，仍為虛偽證言。另外，檢察官在訊問證人乙時，問道：「丙是否
跟你提過行賄計畫？」乙身為丙的親信兼好友，為了幫丙脫罪，向檢察
官虛偽證稱：「我跟丙早已多年沒有往來。」甲、乙均在供述後踐行具結
程序。試問甲、乙之刑責？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "5f10b1dfba27", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法實務", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00061', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-a9c8f8e6', 'sub-policepromo-8b7f1efc-01', NULL, 'essay', '律師 A接受被告委任，以辯護人身分，於被告受高雄地方檢察署檢察官
訊問時在場陪訊。訊問程序中，檢察官以 A當場書寫筆記過於詳細為由，
認為行為不當足以影響偵查秩序，遂指揮在庭法警扣押 A已製作之訊問
筆記。A對此扣押不服，認為侵害被告受律師協助權，乃具狀向高雄地
方法院提出準抗告，要求檢察官發還受扣押之筆記。請說明 A準抗告之
合法性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "5f10b1dfba27", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法實務", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00062', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-a9c8f8e6', 'sub-policepromo-8b7f1efc-01', NULL, 'essay', '甲透過交友網站認識乙女，兩人相談甚歡，不久即相約在某夜店見面。
甲涉嫌在夜店以藥物迷昏乙女後予以性侵，第二天乙女即到警局報案。
員警丙得知甲乙使用通訊軟體 LINE 作為聯絡工具後，為蒐證目的，經
乙女同意，丙即使用乙之手機，假裝是乙而以 LINE 與甲聯繫。丙以技
巧性問話方式，希望讓甲不自覺而說出犯罪。甲果而中計，在對話過程
中坦承犯行。丙將該 LINE 對話內容予以截圖，作為甲犯罪之證據。案
經檢察官對甲提起公訴。甲以該 LINE 對話係受警員誘騙，不能作為證
據。經審理後，法院仍採認該證據作為甲有罪判決之依據，請以實務見
解及刑事訴訟學理，試述法院有罪判決採證之合法性。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "5f10b1dfba27", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0303", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑法與刑事訴訟法實務", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00063', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於行政法法源之敘述，下列何者錯誤？', '["不當得利之法理亦為行政法之不成文法法源", "行政法法源包括成文法體系及不成文法體系", "兒童權利公約非屬行政法法源", "憲法判決為行政法法源"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00064', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於法律優位原則之敘述，下列何者正確？', '["地方自治團體就委辦事項，可基於法律之授權，訂定自治條例或自治規則，不受中央主管機關法規 命令之拘束", "行政機關訂定行政命令，不得牴觸法律授權範圍及意旨，但基於執行必要，可限縮法律之適用", "行政行為應受法律之拘束，法律應僅限於立法院通過並經總統公布者", "在行政法之成文法規範體系中，憲法效力最高，法律次之，行政命令再次之，自治規章居於最下位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00065', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '關於地方自治團體所定自治法規或委辦規則之敘述，下列何者錯誤？', '["地方議會所定自律規則，與上級自治法規牴觸時，基於尊重議會自律，仍為有效", "自治條例與憲法、法律牴觸者，係違反法律優位原則，為無效", "委辦規則與憲法、法律、中央法令牴觸者，無效", "自治法規與憲法、法律、基於法律授權之法規、上級自治團體自治條例或該自治團體自治條例有無 牴觸發生疑義時，得聲請司法院解釋之"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00066', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何種事項非屬私經濟行政？', '["勞動部發放「部分工時受僱勞工生活補貼」", "地方自治團體標售公有非公用土地", "經濟部出售中鋼股票", "臺灣銀行基於與退除役軍職人員所訂立之優惠存款契約，給付優惠存款利息"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00067', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '下列何者非屬公權力行政？', '["行政機關依政府採購法與公營事業締結勞務採購契約", "經濟部依促進民間參與公共建設法與民間機構締結海水淡化廠BOT投資契約", "衛生福利部辦理疫苗採購及預防接種", "中央流行疫情指揮中心成立期間，各級政府機關依指揮官之指示，向民間機構徵用或調用防疫器具、 設備、藥品、醫療器材等"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('policepromo-8b7f1efc-moex-00068', 'policepromo-8b7f1efc', 'policepromo-8b7f1efc-moex-111-3082b5f1', 'sub-policepromo-8b7f1efc-02', NULL, 'single_choice', '依司法院大法官解釋及現行法之規定，關於受刑人在監關係之敘述，下列何者錯誤？', '["假釋人對於法務部撤銷假釋之處分，不得直接聲明不服，僅得就檢察官關於假釋撤銷後執行殘刑之 指揮，依刑事訴訟法第484條規定向普通法院刑事庭聲明異議", "受刑人因監獄行刑而不服監獄所為影響其個人權益之處分或管理措施時，得以書面或言詞向監獄提 起申訴", "受刑人因監獄行刑而不服監獄所為影響其個人權益之處分或管理措施，如因已執行而無回復原狀可 能或已消滅，但有即受確認判決之法律上利益者，仍可向監獄所在地之地方法院行政訴訟庭提起確 認處分違法之訴訟", "受刑人認為監獄處分逾越達成監獄行刑目的所必要之範圍，而不法侵害其憲法所保障之基本權利且 非顯屬輕微者，經依法向監督機關提起申訴而不服其決定者，可向監獄所在地之地方法院行政訴訟 庭提起撤銷訴訟"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:26+00:00", "source_pdf_sha1": "cad2635c5595", "answer_pdf_sha1": "e2e4f43c2655", "source_family": "moex-gov-tw", "moex": {"exam_code": "111170", "c": "101", "s": "0204", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法", "year": "111", "exam_name": "111年警察人員升官等考試、111年交通事業郵政人員升資考試、111年交通事業公路人員升資考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "policepromo", "civil_category": "行政警察人員"}'::jsonb, NULL)
